@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@{
    var context = new HoverCardContext(
        EffectiveOpen || _pinned,
        EventCallback.Factory.Create(this, RequestOpen),
        EventCallback.Factory.Create(this, RequestClose),
        EventCallback.Factory.Create(this, TogglePin),
        _wrapperId);
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="relative inline-block" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter] public int OpenDelay { get; set; } = 200;
    [Parameter] public int CloseDelay { get; set; } = 300;
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("hovercard");
    private readonly DelayedDispatch _dispatch = new();
    // rc.44 — tap-pin path for touch devices. The trigger's @onclick toggles
    // _pinned; click-outside auto-unpins via the global mousedown/touchstart
    // listener in components.js.
    private bool _pinned;
    private bool _clickOutsideRegistered;

    // battle-wave2 #81 (state-on-data-change) — live hover/open state lives in
    // this private backing field, NEVER in the [Parameter] Open. Writing hover
    // state into the parameter meant (a) a consumer-supplied Open=true was
    // overwritten the moment the pointer left, and (b) an unrelated parent
    // re-render re-pushed the old Open literal and reverted the user's hover.
    // The backing field is reseeded from Open only when the parent genuinely
    // changes it (see SetParametersAsync), mirroring the Dialog precedent.
    private bool _open;
    private bool _lastOpenParam;
    private bool _hasOpenParam;
    // CONTROLLED discriminator: the last value WE pushed UP via OpenChanged (also
    // re-synced whenever we adopt an authoritative Open). A controlled parent
    // re-render that echoes back this exact value is safe to ignore (keep the
    // in-flight hover/pin state); any other value is an authoritative assertion
    // (veto / normalization / reset) and must win — see Switch.razor.
    private bool _lastPushed;

    private bool EffectiveOpen => _open;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        // The legacy IsOpen alias is obsolete but still a valid bound parameter,
        // so honour it when reseeding (suppress CS0618 for the nameof probe).
#pragma warning disable CS0618
        var hasOpen = parameters.TryGetValue<bool>(nameof(Open), out var incomingOpen)
            || parameters.TryGetValue<bool>(nameof(IsOpen), out incomingOpen);
#pragma warning restore CS0618

        if (hasOpen)
        {
            if (!_hasOpenParam)
            {
                // First observation: seed unconditionally before the initial render.
                _open = incomingOpen;
                _lastPushed = incomingOpen;
            }
            else if (OpenChanged.HasDelegate)
            {
                // CONTROLLED: the parent owns the value. Echo of our own push
                // (Open == _lastPushed) → keep the in-flight hover/pin state.
                // Anything else (veto, normalization, reset) → adopt the parent's
                // assertion, even if it equals the value the user just left behind.
                if (incomingOpen != _lastPushed)
                {
                    _open = incomingOpen;
                    _lastPushed = incomingOpen;
                }
            }
            else if (incomingOpen != _lastOpenParam)
            {
                // UNCONTROLLED: component owns the live value. Reseed only on a
                // real change of the supplied Open value; a same-value re-render
                // must NOT clobber a live hover/open state.
                _open = incomingOpen;
                _lastPushed = incomingOpen;
            }

            _lastOpenParam = incomingOpen;
            _hasOpenParam = true;
        }

        return base.SetParametersAsync(parameters);
    }

    private void RequestOpen()
    {
        _dispatch.Cancel();
        if (EffectiveOpen) return;
        _dispatch.Schedule(OpenDelay, () => InvokeAsync(async () =>
        {
            // Write the live open-state to the backing field, never to the
            // [Parameter] Open. OpenChanged still notifies two-way consumers.
            // Record _lastPushed BEFORE invoking: a controlled parent re-renders
            // synchronously inside InvokeAsync, so SetParametersAsync must already
            // see this value as "the value we just pushed" to distinguish an
            // accepted echo (keep in-flight state) from a veto (roll back).
            _open = true;
            _lastPushed = true;
            await OpenChanged.InvokeAsync(true);
            StateHasChanged();
        }));
    }

    private void RequestClose()
    {
        // If the card is pinned (touch), hover-leave must NOT close it.
        if (_pinned) return;
        _dispatch.Cancel();
        if (!EffectiveOpen) return;
        _dispatch.Schedule(CloseDelay, () => InvokeAsync(async () =>
        {
            // See RequestOpen: record _lastPushed before invoking so a
            // synchronous controlled-parent veto is detectable on re-render.
            _open = false;
            _lastPushed = false;
            await OpenChanged.InvokeAsync(false);
            StateHasChanged();
        }));
    }

    private async Task TogglePin()
    {
        _pinned = !_pinned;
        if (_pinned)
        {
            // Stop any in-flight close-delay so the tap reliably keeps it open.
            _dispatch.Cancel();
            if (!_clickOutsideRegistered)
            {
                await Interop.RegisterClickOutside(_wrapperId, null, OnClickOutside);
                _clickOutsideRegistered = true;
            }
        }
        else
        {
            // battle-wave2 #179 (lifecycle) — unpin must release the global
            // click-outside listener, not just flip _pinned. The old code only
            // unregistered in DisposeAsync, so after one pin/unpin cycle the
            // listener stayed wired for the component's whole life. The next pin
            // re-registers lazily via the `if (!_clickOutsideRegistered)` guard.
            await UnregisterClickOutsideIfNeeded();
            // Optional auto-collapse on unpin if the user wasn't hovering.
            if (EffectiveOpen)
            {
                // See RequestOpen: record _lastPushed before invoking so a
                // synchronous controlled-parent veto is detectable on re-render.
                _open = false;
                _lastPushed = false;
                await OpenChanged.InvokeAsync(false);
            }
        }
        StateHasChanged();
    }

    // 2.2.3: switched from `_ = OpenChanged.InvokeAsync(false)` fire-and-forget
    // to an awaited invocation so consumer-handler failures aren't swallowed
    // on an unobserved task. Click-outside dispatch is async-aware, so the
    // method returning Task is fine.
    private async Task OnClickOutside()
    {
        if (_pinned)
        {
            _pinned = false;
            // battle-wave2 #179 (lifecycle) — auto-unpin must also unregister the
            // click-outside listener so it doesn't linger after the card closes.
            await UnregisterClickOutsideIfNeeded();
            if (EffectiveOpen)
            {
                // See RequestOpen: record _lastPushed before invoking so a
                // synchronous controlled-parent veto is detectable on re-render.
                _open = false;
                _lastPushed = false;
                await OpenChanged.InvokeAsync(false);
            }
            StateHasChanged();
        }
    }

    // battle-wave2 #179 (lifecycle) — shared teardown for the global click-outside
    // listener, idempotent so unpin, click-outside and dispose can all call it.
    // Resetting _clickOutsideRegistered lets the next pin re-register lazily.
    private async Task UnregisterClickOutsideIfNeeded()
    {
        if (!_clickOutsideRegistered) return;
        try { await Interop.UnregisterClickOutside(_wrapperId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        _clickOutsideRegistered = false;
    }

    public async ValueTask DisposeAsync()
    {
        _dispatch.Dispose();
        await UnregisterClickOutsideIfNeeded();
    }

    public record HoverCardContext(bool IsOpen, EventCallback RequestOpen, EventCallback RequestClose, EventCallback RequestTogglePin, string WrapperId);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.IsOpen)
{
    <div id="@_contentId" class="@CssClass" @onmouseenter="() => Context.RequestOpen.InvokeAsync()" @onmouseleave="() => Context.RequestClose.InvokeAsync()" @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses"></div>
        }
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public HoverCard.HoverCardContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Align Align { get; set; } = Lumeo.Align.Center;
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Bottom;
    [Parameter] public bool ShowArrow { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("hovercard-content");
    // battle-wave2 #80 (state-on-data-change) — track the last anchor we actually
    // positioned against instead of a one-shot bool. A Side/Align change while the
    // card is OPEN must re-run PositionFixed; the old `_positioned` latch pinned the
    // card to its first-open placement forever. null == not currently positioned.
    private (string Side, string Align)? _appliedAnchor;

    private string CssClass => Cx.Merge(
        "fixed z-50 w-64 rounded-md border border-border/60 bg-popover p-4 text-popover-foreground shadow-lg outline-none",
        ShowArrow ? "overflow-visible" : "",
        "animate-fade-in",
        Class);

    private string ArrowClasses => Side switch
    {
        Lumeo.Side.Top => "absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-r border-border/60",
        Lumeo.Side.Bottom => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60",
        Lumeo.Side.Left => "absolute top-1/2 left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-r border-border/60",
        Lumeo.Side.Right => "absolute top-1/2 right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-l border-border/60",
        _ => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60"
    };

    private string AlignStr => Align switch
    {
        Lumeo.Align.Start => "start",
        Lumeo.Align.Center => "center",
        Lumeo.Align.End => "end",
        _ => "center"
    };

    private string SideStr => Side switch
    {
        Lumeo.Side.Top => "top",
        Lumeo.Side.Bottom => "bottom",
        Lumeo.Side.Left => "left",
        Lumeo.Side.Right => "right",
        _ => "bottom"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen)
        {
            // Re-position whenever the anchor (Side/Align) differs from what we last
            // applied — covers both the first open AND a Side/Align change while the
            // card stays open. Equality on the tuple keeps a same-anchor re-render
            // from churning the floating-ui placement.
            var anchor = (SideStr, AlignStr);
            if (_appliedAnchor != anchor)
            {
                await Interop.PositionFixed(_contentId, Context.WrapperId, AlignStr, false, SideStr);
                _appliedAnchor = anchor;
            }
        }
        else if (_appliedAnchor is not null)
        {
            try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
            _appliedAnchor = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_appliedAnchor is not null)
        {
            try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
            _appliedAnchor = null;
        }
    }

}

@namespace Lumeo

@if (AsChild)
{
    @* asChild: render NO wrapper. Cascade the slot so a cooperating child (a Lumeo
       <Button>, or a manual <ChildContentSlot> splat) becomes the single trigger
       element — the hover/focus/pin handlers and aria-expanded fold onto the child's
       real control. HoverCard positions against its root wrapper (Context.WrapperId),
       not this trigger, so dropping the wrapper does not affect positioning. *@
    <CascadingValue Value="Slot" IsFixed="false">
        @if (ChildContentSlot is not null)
        {
            @ChildContentSlot(Slot)
        }
        else
        {
            @ChildContent
        }
    </CascadingValue>
}
else
{
    @* focusin/focusout give keyboard users parity with hover (Radix opens the card
       on focus and closes on blur). They sit on the wrapper, so focusing the
       trigger's inner link/button bubbles up and opens the card; tabbing away fires
       focusout and closes it. The pin/click path (touch) is unaffected. *@
    <div class="@CssClass"
         aria-expanded="@Context.IsOpen"
         @onmouseenter="() => Context.RequestOpen.InvokeAsync()"
         @onmouseleave="() => Context.RequestClose.InvokeAsync()"
         @onfocusin="() => Context.RequestOpen.InvokeAsync()"
         @onfocusout="() => Context.RequestClose.InvokeAsync()"
         @onclick="() => Context.RequestTogglePin.InvokeAsync()"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] public HoverCard.HoverCardContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Tier-2 escape hatch for <see cref="AsChild"/> with arbitrary (non-Lumeo) markup:
    /// receives the <see cref="TriggerSlot"/> so the consumer can splat
    /// <c>@attributes="slot.Attributes"</c> and wire <c>@onmouseenter="slot.OnMouseEnter.InvokeAsync"</c>
    /// (etc.) onto their own single element. Lumeo <c>&lt;Button&gt;</c> children need
    /// only <see cref="AsChild"/> — they consume the slot automatically.
    /// </summary>
    [Parameter] public RenderFragment<TriggerSlot>? ChildContentSlot { get; set; }

    /// <summary>
    /// When <c>true</c>, the trigger renders NO wrapper element and instead cascades a
    /// <see cref="TriggerSlot"/> that a cooperating child folds onto its own single root
    /// element — yielding ONE DOM node with the hover/focus open-close handlers, the pin
    /// toggle and <c>aria-expanded</c> forwarded (the Radix <c>asChild</c> goal). The
    /// child must resolve to exactly one cooperating element (a Lumeo <c>&lt;Button&gt;</c>,
    /// or a manual <see cref="ChildContentSlot"/> splat). Default <c>false</c> preserves
    /// the current <c>inline-flex</c> wrapper exactly.
    /// </summary>
    [Parameter] public bool AsChild { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex", Class);

    private TriggerSlot Slot => new(
        Id: null,                                 // HoverCard anchors positioning on its root wrapper, not the trigger
        Class: Cx.Merge("inline-flex", Class),
        Attributes: BuildAttrs(),
        OnClick: EventCallback.Factory.Create<MouseEventArgs>(this, _ => Context.RequestTogglePin.InvokeAsync()),
        OnFocusIn: EventCallback.Factory.Create<FocusEventArgs>(this, _ => Context.RequestOpen.InvokeAsync()),
        OnFocusOut: EventCallback.Factory.Create<FocusEventArgs>(this, _ => Context.RequestClose.InvokeAsync()),
        OnMouseEnter: EventCallback.Factory.Create<MouseEventArgs>(this, _ => Context.RequestOpen.InvokeAsync()),
        OnMouseLeave: EventCallback.Factory.Create<MouseEventArgs>(this, _ => Context.RequestClose.InvokeAsync()));

    private IReadOnlyDictionary<string, object> BuildAttrs()
    {
        var d = new Dictionary<string, object>
        {
            ["aria-expanded"] = Context.IsOpen ? "true" : "false",
        };
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value; // author wins on collision
        return d;
    }
}
